import "core-js/modules/es.array.push.js";
import { defineComponent, computed } from 'vue';
import { useStore } from 'vuex';
import { useRoute, useRouter } from 'vue-router';
import { HomeFilled, Upload, InfoFilled, User, ArrowDown, Collection, SwitchButton, Reading, Key, UserFilled, Monitor, Document } from '@element-plus/icons-vue';
import { ElMessage } from 'element-plus';
export default defineComponent({
  name: 'HeaderComponent',
  components: {
    HomeFilled,
    Upload,
    InfoFilled,
    User,
    ArrowDown,
    Collection,
    SwitchButton,
    Reading,
    Key,
    UserFilled,
    Monitor,
    Document
  },
  setup() {
    const store = useStore();
    const route = useRoute();
    const router = useRouter();

    // 计算当前激活的菜单项
    const activeIndex = computed(() => route.path);

    // 从store获取登录状态
    const isLoggedIn = computed(() => store.getters['auth/isLoggedIn']);

    // 获取当前用户信息
    const currentUser = computed(() => store.getters['auth/currentUser']);

    // 获取用户显示名称
    const displayName = computed(() => {
      if (!currentUser.value) return '用户';

      // 优先显示昵称，其次是用户名
      return currentUser.value.nickname || currentUser.value.username || currentUser.value.name || '用户';
    });

    // 获取用户头像
    const avatarUrl = computed(() => {
      if (currentUser.value && currentUser.value.avatar) {
        return currentUser.value.avatar;
      }
      // 默认头像
      return 'https://cube.elemecdn.com/0/88/03b0d39583f48206768a7534e55bcpng.png';
    });

    // 检查用户是否为管理员
    const isAdmin = computed(() => {
      if (!currentUser.value || !currentUser.value.roles) {
        return false;
      }
      return currentUser.value.roles.includes('ROLE_ADMIN');
    });

    // 登录功能
    const login = () => {
      router.push('/login');
    };

    // 注册功能
    const register = () => {
      router.push('/register');
    };

    // 登出功能
    const logout = () => {
      store.dispatch('auth/logout');
      router.push('/login');
      ElMessage.success('已退出登录');
    };

    // 跳转到管理员仪表盘
    const goToDashboard = () => {
      router.push('/admin/dashboard');
    };

    // 跳转到个人中心
    const goToProfile = () => {
      router.push('/profile');
    };

    // 跳转到我的小说
    const goToMyNovels = () => {
      router.push('/my-novels');
    };

    // 跳转到系统日志
    const goToSystemLogs = () => {
      router.push('/admin/logs');
    };
    return {
      activeIndex,
      isLoggedIn,
      displayName,
      avatarUrl,
      isAdmin,
      login,
      register,
      logout,
      goToDashboard,
      goToProfile,
      goToMyNovels,
      goToSystemLogs
    };
  }
});
